# Base shapes module - defines abstract base classes and interfaces
interface IMeasurable:
    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

interface IScalable:
    @abstract
    def scale(self, factor: float) -> None:
        ...

@abstract
class Shape:
    _name: str

    def __init__(self, name: str):
        self._name = name

    @virtual
    def get_name(self) -> str:
        return self._name

    @virtual
    def describe(self) -> str:
        return f"Shape: {self._name}"

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

class Rectangle(Shape, IScalable):
    width: float
    height: float

    def __init__(self, name: str, w: float, h: float):
        super().__init__(name)
        self.width = w
        self.height = h

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return f"Rectangle {self._name}: {self.width} x {self.height}"

    @override
    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

