# Advanced shapes module - extends base shapes with specialized implementations
from shapes import Shape, Rectangle, IMeasurable, IScalable
from utils import ShapeType, Point, PI

class Circle(Shape, IScalable):
    _center: Point
    _radius: float

    def __init__(self, name: str, center: Point, radius: float):
        super().__init__(name)
        self._center = center
        self._radius = radius

    @override
    def area(self) -> float:
        return PI * self._radius * self._radius

    @override
    def perimeter(self) -> float:
        return 2.0 * PI * self._radius

    @override
    def describe(self) -> str:
        return f"Circle {self._name} at {self._center} with radius {self._radius}"

    def get_shape_type(self) -> ShapeType:
        return ShapeType.CIRCLE

    @override
    def scale(self, factor: float) -> None:
        self._radius = self._radius * factor

class Square(Rectangle):
    side: float

    def __init__(self, name: str, side_length: float):
        self.side = side_length
        super().__init__(name, side_length, side_length)

    @override
    def describe(self) -> str:
        return f"Square {self._name}: side = {self.side}"

    @override
    def scale(self, factor: float) -> None:
        self.side = self.side * factor
        self.width = self.side
        self.height = self.side

class Triangle(Shape):
    _a: Point
    _b: Point
    _c: Point

    def __init__(self, name: str, p1: Point, p2: Point, p3: Point):
        super().__init__(name)
        self._a = p1
        self._b = p2
        self._c = p3

    @override
    def area(self) -> float:
        return 0.5 * abs((self._b.x - self._a.x) * (self._c.y - self._a.y) - (self._c.x - self._a.x) * (self._b.y - self._a.y))

    @override
    def perimeter(self) -> float:
        ab = self._a.distance_to(self._b)
        bc = self._b.distance_to(self._c)
        ca = self._c.distance_to(self._a)
        return ab + bc + ca

    @override
    def describe(self) -> str:
        return f"Triangle {self._name}"
